import type { HTMLAttributes } from 'react';
export type CounterSizes = 'small' | 'medium';
export interface CounterProps extends HTMLAttributes<HTMLDivElement> {
    /**
     * Выводит переданное количество.
     */
    count?: number | null;
    /**
     * Флаг ошибки.
     */
    error?: boolean;
    /**
     * Выводит пустой кружок без контента.
     */
    hideBadgeContent?: boolean;
    /**
     * Показывает восклицательный знак.
     */
    warning?: boolean;
    /**
     * Всплывающее описание
     */
    tooltipTitle?: string;
    /**
     * Пользовательский класс
     */
    className?: string;
    /**
     * Размер компонента
     */
    size?: CounterSizes;
}
